commands.cmd:
raw=$(cat /var/log/app.log) || { echo "log file unreadable" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  {
    for (i=1; i<=NF; i++) {
      tok=$i
      if (tok ~ /^([A-Za-z_][A-Za-z0-9_]*\.)*[A-Za-z_][A-Za-z0-9_]*(Exception|Error)$/) {
        count[tok]++
      }
    }
  }
  END { for (sig in count) printf "%s\t%d\n", sig, count[sig] }' \
  | sort \
  | awk -F'\t' '
    BEGIN { printf "{\"results\":["; sep="" }
    {
      sig=$1
      gsub(/\\/,"\\\\",sig); gsub(/"/,"\\\"",sig)
      printf "%s{\"signature\":\"%s\",\"count\":%d}", sep, sig, $2
      sep=","
    }
    END { printf "]}" }' || exit 1
